const MANAGED_BY = 'google-contact-birthday-sync';
const CALENDAR_ID = '9b70507aba42b687815ea7e0291431e150247a15d3ba1b4dda66fb9dc888f259@group.calendar.google.com';
const TIMEZONE = 'Europe/Berlin';
const NOTIFICATION_HOUR = 14;
const NOTIFICATION_MINUTE = 0;
const EVENT_DURATION_MINUTES = 30;
const pages = $input.all();

function pad(value) {
  return String(value).padStart(2, '0');
}

function isLeapYear(year) {
  return (year % 4 === 0 && year % 100 !== 0) || year % 400 === 0;
}

function getLocalParts(date, timeZone) {
  const formatter = new Intl.DateTimeFormat('en-CA', {
    timeZone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
    hour12: false,
  });
  const values = {};
  for (const part of formatter.formatToParts(date)) {
    if (part.type !== 'literal') {
      values[part.type] = part.value;
    }
  }
  return {
    year: Number(values.year),
    month: Number(values.month),
    day: Number(values.day),
    hour: Number(values.hour),
    minute: Number(values.minute),
    second: Number(values.second),
  };
}

function getOffsetMinutes(date, timeZone) {
  const formatter = new Intl.DateTimeFormat('en-US', {
    timeZone,
    timeZoneName: 'shortOffset',
    hour: '2-digit',
    minute: '2-digit',
  });
  const zonePart = formatter.formatToParts(date).find((part) => part.type === 'timeZoneName')?.value ?? 'GMT+00:00';
  const match = zonePart.match(/^GMT([+-])(\d{1,2})(?::?(\d{2}))?$/);
  if (!match) {
    throw new Error(`Unable to parse timezone offset: ${zonePart}`);
  }
  const sign = match[1] === '-' ? -1 : 1;
  const hours = Number(match[2]);
  const minutes = Number(match[3] ?? '0');
  return sign * ((hours * 60) + minutes);
}

function toRfc3339InTimeZone(year, month, day, hour, minute, timeZone) {
  let guess = new Date(Date.UTC(year, month - 1, day, hour, minute, 0));
  for (let i = 0; i < 4; i += 1) {
    const local = getLocalParts(guess, timeZone);
    const desiredUtc = Date.UTC(year, month - 1, day, hour, minute, 0);
    const actualUtc = Date.UTC(local.year, local.month - 1, local.day, local.hour, local.minute, local.second);
    const diffMs = desiredUtc - actualUtc;
    if (diffMs === 0) {
      break;
    }
    guess = new Date(guess.getTime() + diffMs);
  }
  const offsetMinutes = getOffsetMinutes(guess, timeZone);
  const sign = offsetMinutes >= 0 ? '+' : '-';
  const absoluteOffset = Math.abs(offsetMinutes);
  const offsetHours = Math.floor(absoluteOffset / 60);
  const offsetRemainderMinutes = absoluteOffset % 60;
  return `${year}-${pad(month)}-${pad(day)}T${pad(hour)}:${pad(minute)}:00${sign}${pad(offsetHours)}:${pad(offsetRemainderMinutes)}`;
}

function addMinutesToRfc3339(rfc3339, minutesToAdd) {
  const date = new Date(rfc3339);
  date.setUTCMinutes(date.getUTCMinutes() + minutesToAdd);
  const offsetMatch = rfc3339.match(/([+-]\d{2}:\d{2}|Z)$/);
  if (!offsetMatch) {
    throw new Error(`Missing offset in RFC3339 string: ${rfc3339}`);
  }
  const offset = offsetMatch[1];
  const offsetMinutes = offset === 'Z'
    ? 0
    : ((offset[0] === '-' ? -1 : 1) * ((Number(offset.slice(1, 3)) * 60) + Number(offset.slice(4, 6))));
  const localTime = new Date(date.getTime() + (offsetMinutes * 60 * 1000));
  return `${localTime.getUTCFullYear()}-${pad(localTime.getUTCMonth() + 1)}-${pad(localTime.getUTCDate())}T${pad(localTime.getUTCHours())}:${pad(localTime.getUTCMinutes())}:00${offset}`;
}

function chooseName(person) {
  const names = person.names ?? [];
  const preferred = names.find((entry) => entry.metadata?.primary) ?? names[0];
  return preferred?.displayName?.trim() || null;
}

function chooseBirthday(person) {
  const birthdays = (person.birthdays ?? [])
    .filter((entry) => entry.date?.month && entry.date?.day)
    .sort((left, right) => {
      const leftScore = left.metadata?.primary ? 0 : 1;
      const rightScore = right.metadata?.primary ? 0 : 1;
      return leftScore - rightScore;
    });
  return birthdays[0] ?? null;
}

const currentYear = new Date().getFullYear();
const targetYears = [currentYear, currentYear + 1];
const desiredEvents = [];
const seenKeys = new Set();
let contactsWithBirthdays = 0;

for (const page of pages) {
  const connections = page.json.connections ?? [];
  for (const person of connections) {
    const contactKey = person.resourceName;
    const name = chooseName(person);
    const birthday = chooseBirthday(person);
    if (!contactKey || !name || !birthday?.date?.month || !birthday?.date?.day) {
      continue;
    }

    contactsWithBirthdays += 1;
    const birthYear = Number.isInteger(birthday.date.year) ? birthday.date.year : null;
    const month = birthday.date.month;
    const day = birthday.date.day;

    for (const eventYear of targetYears) {
      if (month === 2 && day === 29 && !isLeapYear(eventYear)) {
        continue;
      }

      const eventKey = `${contactKey}::${eventYear}`;
      if (seenKeys.has(eventKey)) {
        continue;
      }
      seenKeys.add(eventKey);

      const startDate = `${eventYear}-${pad(month)}-${pad(day)}`;
      const startDateTime = toRfc3339InTimeZone(eventYear, month, day, NOTIFICATION_HOUR, NOTIFICATION_MINUTE, TIMEZONE);
      const endDateTime = addMinutesToRfc3339(startDateTime, EVENT_DURATION_MINUTES);
      const age = birthYear !== null ? eventYear - birthYear : null;
      const summary = age !== null ? `${name} Birthday (${age})` : `${name} Birthday`;

      desiredEvents.push({
        eventKey,
        contactKey,
        eventYear: String(eventYear),
        summary,
        startDate,
        startDateTime,
        endDateTime,
        description: `Managed by ${MANAGED_BY}. Source contact: ${contactKey}`,
        privateProperties: {
          managedBy: MANAGED_BY,
          contactKey,
          eventYear: String(eventYear),
        },
      });
    }
  }
}

desiredEvents.sort((left, right) => left.startDate.localeCompare(right.startDate) || left.summary.localeCompare(right.summary));

return [{
  json: {
    managedBy: MANAGED_BY,
    calendarId: CALENDAR_ID,
    timezone: TIMEZONE,
    windowStart: `${currentYear}-01-01T00:00:00Z`,
    windowEnd: `${currentYear + 2}-01-01T00:00:00Z`,
    targetYears,
    contactsWithBirthdays,
    desiredEventCount: desiredEvents.length,
    desiredEvents,
  },
}];

const summary = $('Normalize Contact Birthdays').first().json;
const pages = $input.all();
const existingEvents = [];
for (const page of pages) {
  for (const event of page.json.items ?? []) {
    existingEvents.push(event);
  }
}

const reminderMinutes = 0;

function buildBody(desired) {
  return {
    summary: desired.summary,
    description: desired.description,
    start: {
      dateTime: desired.startDateTime,
      timeZone: summary.timezone,
    },
    end: {
      dateTime: desired.endDateTime,
      timeZone: summary.timezone,
    },
    extendedProperties: { private: desired.privateProperties },
    reminders: {
      useDefault: false,
      overrides: [
        {
          method: 'popup',
          minutes: reminderMinutes,
        },
      ],
    },
  };
}

function buildDeleteAction(eventKey, existing) {
  return {
    json: {
      operation: 'delete',
      method: 'DELETE',
      url: `https://www.googleapis.com/calendar/v3/calendars/${encodeURIComponent(summary.calendarId)}/events/${encodeURIComponent(existing.id)}`,
      eventKey,
      summary: existing.summary,
      existingEventId: existing.id,
    },
  };
}

function buildCreateAction(desired) {
  return {
    json: {
      operation: 'create',
      method: 'POST',
      url: `https://www.googleapis.com/calendar/v3/calendars/${encodeURIComponent(summary.calendarId)}/events`,
      body: buildBody(desired),
      eventKey: desired.eventKey,
      summary: desired.summary,
    },
  };
}

function hasMatchingReminder(existing) {
  const reminders = existing.reminders ?? {};
  if (reminders.useDefault !== false) {
    return false;
  }
  const overrides = reminders.overrides ?? [];
  return overrides.length === 1
    && overrides[0]?.method === 'popup'
    && overrides[0]?.minutes === reminderMinutes;
}

function isEquivalent(existing, desired) {
  const privateProps = existing.extendedProperties?.private ?? {};
  return existing.summary === desired.summary
    && existing.description === desired.description
    && existing.start?.dateTime === desired.startDateTime
    && existing.start?.timeZone === summary.timezone
    && existing.end?.dateTime === desired.endDateTime
    && existing.end?.timeZone === summary.timezone
    && !existing.start?.date
    && !existing.end?.date
    && privateProps.managedBy === desired.privateProperties.managedBy
    && privateProps.contactKey === desired.privateProperties.contactKey
    && privateProps.eventYear === desired.privateProperties.eventYear
    && hasMatchingReminder(existing);
}

function requiresRecreate(existing) {
  return Boolean(existing.start?.date || existing.end?.date);
}

const existingByKey = new Map();
for (const event of existingEvents) {
  const privateProps = event.extendedProperties?.private ?? {};
  if (privateProps.managedBy !== summary.managedBy || !privateProps.contactKey || !privateProps.eventYear) {
    continue;
  }
  existingByKey.set(`${privateProps.contactKey}::${privateProps.eventYear}`, event);
}

const actions = [];
for (const desired of summary.desiredEvents) {
  const existing = existingByKey.get(desired.eventKey);
  if (!existing) {
    actions.push(buildCreateAction(desired));
    continue;
  }

  if (!isEquivalent(existing, desired)) {
    if (requiresRecreate(existing)) {
      actions.push(buildDeleteAction(desired.eventKey, existing));
      actions.push(buildCreateAction(desired));
    } else {
      actions.push({
        json: {
          operation: 'update',
          method: 'PATCH',
          url: `https://www.googleapis.com/calendar/v3/calendars/${encodeURIComponent(summary.calendarId)}/events/${encodeURIComponent(existing.id)}`,
          body: buildBody(desired),
          eventKey: desired.eventKey,
          summary: desired.summary,
          existingEventId: existing.id,
        },
      });
    }
  }
}

const desiredKeys = new Set(summary.desiredEvents.map((entry) => entry.eventKey));
for (const [eventKey, existing] of existingByKey.entries()) {
  if (desiredKeys.has(eventKey)) {
    continue;
  }
  actions.push(buildDeleteAction(eventKey, existing));
}

return actions;
